#include <c8051f410.h>                  
#include <stdio.h>
#include "C8051F410.h"

#define TIMER0_RELOAD_VALUE -21536 // (65536 - (24.5e6 / 12*1e-6))

unsigned int current_time = 0; // Store current time in milliseconds

void Timer0_ISR(void) interrupt 1  // Timer0 interrupt service routine
{
    current_time++;
    TH0 = (TIMER0_RELOAD_VALUE >> 8); // Reload high byte
    TL0 = (TIMER0_RELOAD_VALUE & 0xff); // Reload low byte

    if (current_time % 1000 == 0) { // Every second
        char time_buff[10];
        sprintf(time_buff, "%05u sec\n", current_time / 1000);
        printf ("%s", time_buff); // Send second information through UART to the host computer
    }
}

void main()
{
    Init_Device(); // Initialize peripherals
    EA = 1; // Enable global interrupts
    printf("Clock started\n");

    while (1) {
        // Main loop does nothing, all work is done in Timer0_ISR
    }
}

void PCA_Init()
{
    PCA0MD    &= ~0x40;
    PCA0MD    = 0x00;
}

void Timer_Init()
{
    TMOD      = 0x01;          // Timer0: Mode 1, 16-bit
    CKCON     = 0x08;          // Timer0 uses SYSCLK/12
    TL0       = (TIMER0_RELOAD_VALUE & 0xff); // Set reload value to initial counter value
    TH0       = (TIMER0_RELOAD_VALUE >> 8);   // Set reload value to initial counter value
    ET0       = 1;             // Enable Timer0 interrupt
    TR0       = 1;             // Start Timer0
}

void UART_Init()
{
    SCON0     = 0x10;
}

void Port_IO_Init()
{
    // P0.4  -  TX0 (UART0), Push-Pull,  Digital
    // P0.5  -  RX0 (UART0), Open-Drain, Digital
    P0MDOUT   = 0x10;
    XBR0      = 0x01;
    XBR1      = 0x40;
}

void Oscillator_Init()
{
    OSCICN    = 0x87;
}

void Interrupts_Init()
{
    IE        = 0x80;
}

void Init_Device(void)
{
    PCA_Init();
    Timer_Init();
    UART_Init();
    Port_IO_Init();
    Oscillator_Init();
    Interrupts_Init();
}
