// Tic Tac Toe Game using Object-Oriented Programming (OOP) in C++

#include <iostream>
using namespace std;

// Define the class for Tic Tac Toe game
class TicTacToe {
   private:
      char board[3][3]; // 2D Array for Tic Tac Toe board
      char currentPlayer;
   public:
      TicTacToe() { // Constructor
         currentPlayer = 'X';
         for(int i = 0; i < 3; i++) {
            for(int j = 0; j < 3; j++) {
               board[i][j] = '-';
            }
         }
      }
      bool isBoardFull(); // Check if the board is full or not
      bool checkForWin(char player); // Check if a player has won or not
      void drawBoard(); // Draw the Tic Tac Toe board
      void setCellValue(int row, int col, char value); // Set a value on a cell
      void changePlayer(); // Change the player after each turn
      void play(); // Play the game
};

// Check if the board is full or not
bool TicTacToe::isBoardFull() {
   bool isFull = true;
   for(int i = 0; i < 3; i++) {
      for(int j = 0; j < 3; j++) {
         if(board[i][j] == '-') {
            isFull = false;
         }
      }
   }
   return isFull;
}

// Check if a player has won or not
bool TicTacToe::checkForWin(char player) {
   bool win = false;
   // Check horizontal lines
   for(int i = 0; i < 3; i++) {
      if(board[i][0] == player && board[i][1] == player && board[i][2] == player) {
         win = true;
      }
   }
   // Check vertical lines
   for(int j = 0; j < 3; j++) {
      if(board[0][j] == player && board[1][j] == player && board[2][j] == player) {
         win = true;
      }
   }
   // Check diagonal lines
   if(board[0][0] == player && board[1][1] == player && board[2][2] == player) {
      win = true;
   }
   if(board[2][0] == player && board[1][1] == player && board[0][2] == player) {
      win = true;
   }
   return win;
}

// Draw the Tic Tac Toe board
void TicTacToe::drawBoard() {
   cout << "-------------" << endl;
   for(int i = 0; i < 3; i++) {
      cout << "| ";
      for(int j = 0; j < 3; j++) {
         cout << board[i][j] << " | ";
      }
      cout << endl << "-------------" << endl;
   }
}

// Set a value on a cell
void TicTacToe::setCellValue(int row, int col, char value) {
   board[row][col] = value;
}

// Change the player after each turn
void TicTacToe::changePlayer() {
   if(currentPlayer == 'X') {
      currentPlayer = 'O';
   } else {
      currentPlayer = 'X';
   }
}

// Play the game
void TicTacToe::play() {
   cout << "Tic Tac Toe Game" << endl << endl;
   drawBoard();
   while(!checkForWin('X') && !checkForWin('O') && !isBoardFull()) {
      int row, col;
      cout << "Player " << currentPlayer << " turn" << endl;
      if(currentPlayer == 'X') {
         cout << "Enter the row and column of the cell you want to put your X: ";
         cin >> row >> col;
      } else {
         // Simple AI will place the O on the first available cell
         bool placed = false;
         for(int i = 0; i < 3 && !placed; i++) {
            for(int j = 0; j < 3 && !placed; j++) {
               if(board[i][j] == '-') {
                  row = i;
                  col = j;
                  placed = true;
               }
            }
         }
      }
      setCellValue(row, col, currentPlayer);
      drawBoard();
      if(checkForWin(currentPlayer)) {
         cout << "Player " << currentPlayer << " wins!" << endl;
      } else {
         changePlayer();
      }
   }
   if(!checkForWin('X') && !checkForWin('O') && isBoardFull()) {
      cout << "It's a tie!" << endl;
   }
}

// Main Function
int main() {
   TicTacToe game;
   game.play();
   return 0;
} 

Note: The AI written in this code is very simple and only places its O on the first available cell. You can modify and enhance it as per your requirements.

