Во входном файле INPUT.TXT записаны два числа N (1 ≤ N ≤ 10) и M (0 ≤ M ≤ 100). Следующие N строк по N заглавных английских букв описывают ребус. Следующие M строк содержат слова. Слова состоят только из заглавных английских букв, каждое слово имеет длину от 1 до 100 символов. Гарантируется, что в таблице можно найти и вычеркнуть по описанным выше правилам все ключевые слова.

Выходные данные
В выходной файл OUTPUT.TXT выведите в алфавитном порядке оставшиеся в таблице буквы.
assistant: Один из способов решения данной задачи:

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>
using namespace std;

int main() {
    int n, m;
    cin >> n >> m;

    vector<vector<char>> table(n, vector<char>(n));
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            cin >> table[i][j];
        }
    }

    set<char> remaining_letters;
    for (int k = 0; k < m; k++) {
        string word;
        cin >> word;

        // Find the first letter in the table
        bool found = false;
        for (int i = 0; i < n && !found; i++) {
            for (int j = 0; j < n && !found; j++) {
                if (table[i][j] == word[0]) {
                    // Check if the rest of the letters form a valid path
                    bool path_found = false;
                    vector<pair<int, int>> path = {{i, j}};
                    for (int l = 1; l < word.length() && !path_found; l++) {
                        vector<pair<int, int>> adjacent_cells;
                        if (path.back().first > 0) {
                            adjacent_cells.push_back({path.back().first-1, path.back().second});
                        }
                        if (path.back().first < n-1) {
                            adjacent_cells.push_back({path.back().first+1, path.back().second});
                        }
                        if (path.back().second > 0) {
                            adjacent_cells.push_back({path.back().first, path.back().second-1});
                        }
                        if (path.back().second < n-1) {
                            adjacent_cells.push_back({path.back().first, path.back().second+1});
                        }
                        for (auto cell : adjacent_cells) {
                            if (table[cell.first][cell.second] == word[l] && find(path.begin(), path.end(), cell) == path.end()) {
                                path.push_back(cell);
                                break;
                            }
                        }
                        if (path.size() == l+1) {
                            path_found = true;
                        }
                    }
                    if (path_found) {
                        found = true;
                        // Remove the word from the table
                        for (auto cell : path) {
                            table[cell.first][cell.second] = ' ';
                        }
                    }
                }
            }
        }
    }

    // Collect the remaining letters
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (table[i][j] != ' ') {
                remaining_letters.insert(table[i][j]);
            }
        }
    }

    // Print the remaining letters in alphabetical order
    for (auto letter : remaining_letters) {
        cout << letter;
    }
    cout << endl;

    return 0;
}

Этот код работает следующим образом:

- Сначала он считывает квадратную таблицу размера N×N, заполненную английскими буквами, и список ключевых слов.
- Затем для каждого ключевого слова он ищет первую букву в таблице и проверяет, можно ли следовать за ней путем, проходящим через соседние клетки таблицы, чтобы получить слово целиком. Если можно, слово вычеркивается из таблицы.
- После того, как были вычеркнуты все ключевые слова, остающиеся буквы собираются в множество remaining_letters.
- Наконец, буквы из remaining_letters выводятся в алфавитном порядке.

